mapper.select:
    /* FileMapper."selectFileMgmtCd" */
    SELECT
	    CONCAT(
	    	#{fileType}
	    	,'-'
	    	,DATE_FORMAT(NOW(), '%Y%m%d')
	    	,'-'
	    	,FNC_CMM_SEQ_NEXTVAL(#{cmpnyCd}, CONCAT('FILE_MGMT_CD', '-', #{fileType}))
    	) AS FILE_MGMT_CD
	FROM DUAL

mapper.insert:
	/* FileMapper.insertFileInfo */	
    INSERT INTO TB_FILE_INFO (
    	CMPNY_CD
    	, FILE_MGMT_CD
    	, FILE_TYPE
    	, FILE_PATH
    	, FILE_EXT
    	, INSERT_NO
    	, INSERT_DATE
    	, UPDATE_NO
    	, UPDATE_DATE
   	)
   	VALUES(
   		#{cmpnyCd}
   		, #{fileMgmtCd}
   		, #{fileType}
   		, #{filePath}
   		, #{fileExt}
		, #{userId}
		, now()
		, #{userId}
		, now() 
   	)
